import {ArrayBufferReader} from './ArrayBufferReader';

export class DATPARTOUT {

    /**
     * Reads a datpartout file.
     * @param {ArrayBuffer} fileBuffer The data.
     * @constructor
     */
    constructor(fileBuffer) {
        this.dataURI = "";
        this.header = {
            signature: "PARTOUT(4.0)RESOURCE",
            appName: "",
            description: "",
            fileSize: 0,
            nGroups: 0,
            tableSize: 0,
            fullWidth: 0 // [4 bytes] unknown2 (some small integer, seen values 0 through 25)
        };

        const reader = new ArrayBufferReader(fileBuffer);

        /**
         * @type {Array<Array>}
         */
        this.groups = [];

        reader.pointer = 21;
        this.header.appName = reader.readString(50);
        this.header.description = reader.readString(100);
        this.header.fileSize = reader.readNumber(4);
        this.header.nGroups = reader.readNumber(2);
        this.header.tableSize = reader.readNumber(2);
        this.header.fullWidth = reader.readNumber(4);

        for (let groupID = 0; groupID < this.header.nGroups; groupID++) {
            const group = [];
            const nEntries = reader.readNumber(1);
            for (let entryID = 0; entryID < nEntries; entryID++) {
                const entry = {
                    type: reader.readNumber(1)
                };
                switch (entry.type) {
                    case 0: // RESOURCE IDENTIFIER
                        entry.data = reader.readNumber(2);
                        break;
                    case 1: // IMAGE
                        entry.dataLength = reader.readNumber(4);
                        entry.tableSize = reader.readNumber(1);
                        entry.width = reader.readNumber(2);
                        entry.height = reader.readNumber(2);
                        entry.fullWidth = reader.readNumber(2);
                        entry.unk3 = reader.readNumber(2);
                        entry.imageSize = reader.readNumber(4);
                        entry.unk4 = reader.readNumber(1);
                        if (entry.unk4 === 5) {
                            entry.lines = [];
                            for (let i = 0; reader.readNumber(2, false) !== 0xFFFF; i++) {
                                entry.lines[i] = {
                                    offset: reader.readNumber(2),
                                    lineSize: reader.readNumber(2),
                                    pixels: [],
                                };
                                for (let j = 0; j < entry.lines[i].lineSize; j++) {
                                    entry.lines[i].pixels[j] = {
                                        dist: reader.readNumber(2),
                                        color: reader.readNumber(1)
                                    };
                                }
                            }
                            entry.endboi = reader.readNumber(2);
                        }
                        else {
                            entry.padding = Math.ceil(-((entry.height * entry.width - entry.imageSize) / entry.height));
                            entry.data = reader.readBytes(entry.imageSize);
                        }
                        break;
                    case 5: // PALETTE
                        entry.dataLength = reader.readNumber(4);
                        entry.data = {
                            colors: []
                        };
                        for (let color = 0; color < entry.dataLength / 4; color++) {
                            entry.data.colors[color] = {};
                            entry.data.colors[color].b = reader.readNumber(1);
                            entry.data.colors[color].g = reader.readNumber(1);
                            entry.data.colors[color].r = reader.readNumber(1);
                            entry.data.colors[color].a = reader.readNumber(1);
                        }
                        break;
                    case 3: // TEXT
                    case 9: // TEXT2
                        entry.dataLength = reader.readNumber(4);
                        entry.data = reader.readString(entry.dataLength);
                        break;
                    case 12: // Z BUFFER DATA
                        entry.dataLength = reader.readNumber(4);
                        entry.unk1 = reader.readNumber(1);
                        entry.width = reader.readNumber(2);
                        entry.height = reader.readNumber(2);
                        entry.fullWidth = reader.readNumber(2);
                        entry.unk3 = reader.readNumber(4);
                        entry.unk4 = reader.readNumber(2);
                        entry.unk5 = reader.readNumber(2);
                        entry.data = [];
                        for (let i = 0; i < entry.fullWidth * entry.height; i++) {
                            entry.data.push(reader.readNumber(2));
                        }
                        break;
                    default:
                        entry.dataLength = reader.readNumber(4);
                        entry.data = reader.readBytes(entry.dataLength);
                        break;
                }
                group.push(entry);
            }
            this.groups.push(group);
        }
    }
}
